// classify maps a live call outcome into PASS / SKIP / FAIL buckets and
// appends a CellRecord for the agreement-check JSON artifact.
func classify(endpoint, mode, declaredMinTier, rationale string, v interface{}, err error, dur time.Duration, pass, skip, fail *int, records []CellRecord) []CellRecord {
	label := endpoint + "::" + mode
	rec := CellRecord{Endpoint: endpoint, Mode: mode, Rationale: rationale, RowCount: goRowCount(v), DurationMS: dur.Milliseconds()}
	if err == nil {
		fmt.Printf("  %-60s PASS\n", label)
		*pass++
		rec.Status = "PASS"
		return append(records, rec)
	}
	lowered := strings.ToLower(err.Error())
	// Per-call deadline elapsed: SDK cancelled the in-flight gRPC stream
	// (the next cell runs normally on the same *Client).
	if strings.Contains(lowered, "request deadline exceeded") {
		secs := int(dur / time.Second)
		fmt.Printf("  %-60s FAIL  timeout after %ds\n", label, secs)
		*fail++
		rec.Status = "FAIL"
		rec.Detail = fmt.Sprintf("timeout after %ds", secs)
		rec.RowCount = 0
		return append(records, rec)
	}
	if strings.Contains(lowered, "permission") || strings.Contains(lowered, "subscription") {
		fmt.Printf("  %-60s SKIP: tier-permission (declared min_tier=%s)\n", label, declaredMinTier)
		*skip++
		rec.Status = "SKIP"
		rec.Detail = "tier-permission"
		rec.RowCount = 0
		return append(records, rec)
	}
	if strings.Contains(lowered, "no data found") {
		fmt.Printf("  %-60s PASS  (no data)\n", label)
		*pass++
		rec.Status = "PASS"
		rec.Detail = "no data"
		rec.RowCount = 0
		return append(records, rec)
	}
	fmt.Printf("  %-60s FAIL  %v\n", label, err)
	*fail++
	rec.Status = "FAIL"
	// gRPC / transport errors can contain embedded newlines; escape them
	// so the agreement-table row stays single-line.
	detail := strings.ReplaceAll(err.Error(), "\n", "\\n")
	detail = strings.ReplaceAll(detail, "\r", "\\r")
	if len(detail) > 200 {
		detail = detail[:200]
	}
	rec.Detail = detail
	rec.RowCount = 0
	return append(records, rec)
}
